class Review(Base):
    __tablename__ = 'review'

    id = Column(Integer, primary_key=True)
    product_id = Column(Integer)
    rating = Column(Integer)
    text = Column(String)


class Image(Base):
    __tablename__ = 'image'

    id = Column(Integer, primary_key=True)
